import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

// Layout
import MainLayout from "./layouts/MainLayout";

// Pages — Standalone landing
import Home from "./pages/Home";

// Pages — Layout-wrapped (Navbar + Footer)
import Dashboard from "./pages/Dashboard";
import UserProfile from "./pages/userManagement/UserProfile";
import UpdateProfile from "./pages/userManagement/UpdateProfile";

// Pages — Auth (standalone, no Navbar/Footer)
import Register from "./pages/userManagement/Register";
import Login from "./pages/userManagement/Login";

import "./App.css";

function App() {
  return (
    <Router>
      <Routes>
        {/* ── Home (standalone — has its own Navbar for the hero effect) ─── */}
        <Route path="/" element={<Home />} />

        {/* ── Layout Routes (Navbar + Footer via MainLayout <Outlet>) ─────── */}
        <Route element={<MainLayout />}>
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/userProfile" element={<UserProfile />} />
          <Route path="/updateProfile/:id" element={<UpdateProfile />} />
        </Route>

        {/* ── Auth Routes (standalone, full-screen) ────────────────────────── */}
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
      </Routes>
    </Router>
  );
}

export default App;
